  (forall k | 0 <= k < |restrictions| ::
    forall j | restrictions[k].0 - 1 <= j < restrictions[k].1 ::
      0 <= j < n ==> a[j] <= restrictions[k].2)
}

// Total profit: sum of squared heights
ghost function Profit(a: seq<int>): int
  decreases |a|
